def is_ip_blocked(ip_str: str) -> bool:
    """Check if an IP address falls within any blocked network range."""
    try:
        ip = ipaddress.ip_address(ip_str)
        for network in BLOCKED_IP_NETWORKS:
            if ip in network:
                return True
        # Also check if it's private/reserved/loopback using stdlib
        if ip.is_private or ip.is_reserved or ip.is_loopback or ip.is_link_local or ip.is_multicast:
            return True
        return False
    except ValueError:
        # If we can't parse it, block it
        return True


def is_hostname_blocked(hostname: str) -> bool:
    """Check if a hostname matches any blocked patterns."""
    for pattern in BLOCKED_HOSTNAME_PATTERNS:
        if pattern.match(hostname):
            return True
    return False


def validate_url(url: str) -> str:
    """
    Comprehensive URL validation to prevent SSRF attacks.
    
    Returns the validated URL string.
    Raises SSRFError or URLValidationError on failure.
    """
    if not url or not isinstance(url, str):
        raise URLValidationError("URL must be a non-empty string")

    url = url.strip()

    if len(url) > MAX_URL_LENGTH:
        raise URLValidationError(f"URL exceeds maximum length of {MAX_URL_LENGTH}")

    # Parse the URL
    try:
        parsed = urlparse(url)
    except Exception:
        raise URLValidationError("Failed to parse URL")

    # Validate scheme
    if parsed.scheme.lower() not in ALLOWED_SCHEMES:
        raise SSRFError(f"Scheme '{parsed.scheme}' is not allowed. Only {ALLOWED_SCHEMES} are permitted.")

    # Ensure hostname exists
    hostname = parsed.hostname
    if not hostname:
        raise URLValidationError("URL must contain a valid hostname")

    # Strip any userinfo (user:pass@host) - this is an SSRF bypass technique
    if parsed.username or parsed.password or "@" in (parsed.netloc or ""):
        raise SSRFError("URLs with credentials/userinfo are not allowed")

    # Check for backslashes and other bypass characters
    if "\\" in url or "\t" in url or "\n" in url or "\r" in url:
        raise SSRFError("URL contains invalid characters")

    # Check port
    port = parsed.port
    if port is not None and port not in ALLOWED_PORTS:
        raise SSRFError(f"Port {port} is not allowed. Only ports {ALLOWED_PORTS} are permitted.")

    # Check if hostname itself is a blocked pattern
    if is_hostname_blocked(hostname):
        raise SSRFError(f"Hostname '{hostname}' is blocked")

    # Check if hostname is a raw IP address
    try:
        ip = ipaddress.ip_address(hostname)
        if is_ip_blocked(str(ip)):
            raise SSRFError(f"IP address '{hostname}' is in a blocked range")
    except ValueError:
        # Not a raw IP, it's a domain name - resolve it
        pass

    # DNS resolution check - resolve the hostname and verify all IPs are safe
    # This prevents DNS rebinding and ensures the domain doesn't point to internal IPs
    try:
        addrinfo = socket.getaddrinfo(hostname, port or 443, proto=socket.IPPROTO_TCP)
    except socket.gaierror:
        raise URLValidationError(f"Could not resolve hostname '{hostname}'")

    if not addrinfo:
        raise URLValidationError(f"No addresses found for hostname '{hostname}'")

    for family, socktype, proto, canonname, sockaddr in addrinfo:
        resolved_ip = sockaddr[0]
        if is_ip_blocked(resolved_ip):
            raise SSRFError(
                f"Hostname '{hostname}' resolves to blocked IP '{resolved_ip}'. "
                "Access to internal/private networks is not allowed."
            )

    return url


def resolve_and_check_for_rebinding(hostname: str, port: int = 443) -> list:
    """
    Resolve hostname and return safe IP addresses.
    Performs double-resolution to detect DNS rebinding attacks.
    """
    results = []

    for attempt in range(2):
        try:
            addrinfo = socket.getaddrinfo(hostname, port, proto=socket.IPPROTO_TCP)
        except socket.gaierror:
            raise URLValidationError(f"Could not resolve hostname '{hostname}'")

        ips = set()
        for family, socktype, proto, canonname, sockaddr in addrinfo:
            resolved_ip = sockaddr[0]
            if is_ip_blocked(resolved_ip):
                raise SSRFError(
                    f"Hostname '{hostname}' resolves to blocked IP '{resolved_ip}'"
                )
            ips.add(resolved_ip)

        results.append(ips)

        if attempt == 0:
            time.sleep(0.1)  # Small delay between resolutions

    # Check that both resolutions returned safe IPs (already checked above)
    # If the sets differ significantly, it could be DNS rebinding
    if results[0] != results[1]:
        # IPs changed between resolutions - possible DNS rebinding
        logger.warning(
            f"DNS rebinding suspected for {hostname}: "
            f"first={results[0]}, second={results[1]}"
        )
        # Still allow if all IPs in both sets are safe (already verified above)

    return list(results[1])


def get_s3_client():
    """Create and return an S3 client."""
    return boto3.client("s3", region_name=S3_REGION)


def create_headless_browser():
    """Create a headless Chrome browser instance with security hardening."""
    chrome_options = Options()
    chrome_options.binary_location = CHROME_BINARY_PATH
    chrome_options.add_argument("--headless=new")
    chrome_options.add_argument("--no-sandbox")
    chrome_options.add_argument("--disable-dev-shm-usage")
    chrome_options.add_argument("--disable-gpu")
    chrome_options.add_argument("--disable-extensions")
    chrome_options.add_argument("--disable-plugins")
    chrome_options.add_argument(f"--window-size={THUMBNAIL_WIDTH},{THUMBNAIL_HEIGHT}")

    # Security hardening
    chrome_options.add_argument("--disable-background-networking")
    chrome_options.add_argument("--disable-default-apps")
    chrome_options.add_argument("--disable-sync")
    chrome_options.add_argument("--disable-translate")
    chrome_options.add_argument("--disable-web-security=false")
    chrome_options.add_argument("--no-first-run")
    chrome_options.add_argument("--safebrowsing-disable-auto-update")
    chrome_options.add_argument("--disable-file-system")
    chrome_options.add_argument("--disable-notifications")
    chrome_options.add_argument("--disable-popup-blocking")

    # Prevent Chrome from accessing local resources
    chrome_options.add_argument("--disable-local-storage")
    chrome_options.add_argument("--disable-session-storage")

    # Set a standard user agent
    chrome_options.add_argument(
        "--user-agent=Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 "
        "(KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36 ScreenshotBot/1.0"
    )

    service = Service(executable_path=CHROME_DRIVER_PATH)
    driver = webdriver.Chrome(service=service, options=chrome_options)
    driver.set_page_load_timeout(SCREENSHOT_TIMEOUT)
    driver.set_script_timeout(SCREENSHOT_TIMEOUT)

    return driver


def take_screenshot(url: str) -> bytes:
    """Take a screenshot of the given URL using headless Chrome."""
    driver = None
    try:
        driver = create_headless_browser()
        driver.get(url)

        # Wait a moment for page to render
        time.sleep(2)

        # After page load, check the final URL to prevent redirects to internal resources
        final_url = driver.current_url
        if final_url and final_url != url:
            try:
                validate_url(final_url)
            except (SSRFError, URLValidationError) as e:
                raise SSRFError(
                    f"Page redirected to a blocked URL: {final_url}. Reason: {e}"
                )

        screenshot_png = driver.get_screenshot_as_png()
        return screenshot_png

    finally:
        if driver:
            try:
                driver.quit()
            except Exception:
                pass


def upload_to_s3(screenshot_data: bytes, key: str) -> str:
    """Upload screenshot to S3 and return the URL."""
    s3_client = get_s3_client()

    s3_client.put_object(
        Bucket=S3_BUCKET,
        Key=key,
        Body=screenshot_data,
        ContentType="image/png",
        CacheControl="public, max-age=86400",
        # Make it accessible via CloudFront or direct S3 URL
    )

    # Generate a presigned URL (expires in 1 hour)
    presigned_url = s3_client.generate_presigned_url(
        "get_object",
        Params={"Bucket": S3_BUCKET, "Key": key},
        ExpiresIn=3600,
    )

    return presigned_url


