@app.route("/screenshot", methods=["POST"])
def screenshot():
    """
    Take a screenshot of a URL and return the S3 URL.
    
    Request body:
        {"url": "https://example.com"}
    
    Response:
        {"screenshot_url": "https://...", "key": "screenshots/..."}
    """
    data = request.get_json()
    if not data or "url" not in data:
        return jsonify({"error": "Missing 'url' in request body"}), 400

    target_url = data["url"]

    # Step 1: Validate URL against SSRF
    try:
        validated_url = validate_url(target_url)
    except SSRFError as e:
        logger.warning(f"SSRF attempt blocked: {target_url} - {e}")
        return jsonify({"error": f"URL blocked for security reasons: {e}"}), 403
    except URLValidationError as e:
        return jsonify({"error": f"Invalid URL: {e}"}), 400

    # Step 2: Double-check DNS resolution for rebinding protection
    parsed = urlparse(validated_url)
    hostname = parsed.hostname
    port = parsed.port or (443 if parsed.scheme == "https" else 80)

    try:
        safe_ips = resolve_and_check_for_rebinding(hostname, port)
    except SSRFError as e:
        logger.warning(f"SSRF via DNS rebinding blocked: {target_url} - {e}")
        return jsonify({"error": f"URL blocked for security reasons: {e}"}), 403
    except URLValidationError as e:
        return jsonify({"error": f"Invalid URL: {e}"}), 400

    logger.info(f"Taking screenshot of validated URL: {validated_url} (resolves to: {safe_ips})")

    # Step 3: Take screenshot
    try:
        screenshot_data = take_screenshot(validated_url)
    except SSRFError as e:
        logger.warning(f"SSRF via redirect blocked: {target_url} - {e}")
        return jsonify({"error": f"URL blocked for security reasons: {e}"}), 403
    except Exception as e:
        logger.error(f"Screenshot failed for {validated_url}: {e}")
        return jsonify({"error": "Failed to capture screenshot"}), 500

    if not screenshot_data:
        return jsonify({"error": "Screenshot returned empty data"}), 500

    # Step 4: Upload to S3
    screenshot_id = str(uuid.uuid4())
    s3_key = f"screenshots/{screenshot_id}.png"

    try:
        screenshot_url = upload_to_s3(screenshot_data, s3_key)
    except Exception as e:
        logger.error(f"S3 upload failed: {e}")
        return jsonify({"error": "Failed to store screenshot"}), 500

    logger.info(f"Screenshot stored: {s3_key} for URL: {validated_url}")

    return jsonify({
        "screenshot_url": screenshot_url,
        "key": s3_key,
        "original_url": validated_url,
    }), 200


@app.route("/validate", methods=["POST"])
def validate():
    """
    Validate a URL without taking a screenshot.
    Useful for pre-validation on the client side.
    """
    data = request.get_json()
    if not data or "url" not in data:
        return jsonify({"error": "Missing 'url' in request body"}), 400

    target_url = data["url"]

    try:
        validated_url = validate_url(target_url)
        return jsonify({"valid": True, "url": validated_url}), 200
    except SSRFError as e:
        return jsonify({"valid": False, "error": f"Blocked: {e}"}), 403
    except URLValidationError as e:
        return jsonify({"valid": False, "error": f"Invalid: {e}"}), 400


# Rate limiting (simple in-memory, use Redis in production)
from collections import defaultdict
import threading

_rate_limit_lock = threading.Lock()
_rate_limits = defaultdict(list)
RATE_LIMIT_WINDOW = 60  # seconds
RATE_LIMIT_MAX_REQUESTS = 10  # per window


@app.before_request
def rate_limit():
    """Simple rate limiting by IP address."""
    if request.endpoint in ("health_check",):
        return None

    client_ip = request.remote_addr
    now = time.time()

    with _rate_limit_lock:
        # Clean old entries
        _rate_limits[client_ip] = [
            t for t in _rate_limits[client_ip]
            if now - t < RATE_LIMIT_WINDOW
        ]

        if len(_rate_limits[client_ip]) >= RATE_LIMIT_MAX_REQUESTS:
            return jsonify({
                "error": "Rate limit exceeded. Please try again later."
            }), 429

        _rate_limits[client_ip].append(now)

    return None


